view_lkml:
view: risk_pers_acct_history {
  sql_table_name: `axp-lumi.dw.risk_pers_acct_history` ;;

  dimension: acct_cust_xref_id {
    primary_key: yes
    type: string
    sql: ${TABLE}.acct_cust_xref_id ;;
    label: "Account Customer Cross-Reference ID"
    description: "Unique account-to-customer cross-reference identifier used as the join key for credit and product enrichment."
  }

  dimension: acct_bus_unit_cd {
    type: number
    sql: ${TABLE}.acct_bus_unit_cd ;;
    label: "Business Unit Code"
    description: "Numeric business unit code partitioning the account portfolio. Codes 1 and 2 designate consumer business units."
  }

  dimension: acct_srce_sys_cd {
    type: string
    sql: ${TABLE}.acct_srce_sys_cd ;;
    label: "Source System Code"
    description: "Source system identifier for the account record. TRIUMPH is the canonical source for consumer risk reporting."
  }

  dimension_group: acct_as_of {
    type: time
    timeframes: [raw, date, week, month, quarter, year]
    datatype: date
    convert_tz: no
    sql: ${TABLE}.acct_as_of_dt ;;
    description: "Snapshot date for the account history record, aligned to monthly credit and product reporting cycles."
  }

  measure: total_ar {
    type: sum
    sql: ${TABLE}.acct_bill_bal_mth01_amt ;;
    label: "Total Accounts Receivable"
    description: "Sum of month-one billed balance across selected accounts in USD; the canonical AR measure for the portfolio."
    value_format_name: usd
  }

  measure: total_writeoffs {
    type: sum
    sql: ${TABLE}.acct_wrt_off_am ;;
    label: "Total Write-offs"
    description: "Sum of write-off amounts in USD across selected accounts during the reporting period."
    value_format_name: usd
  }

  measure: total_recoveries {
    type: sum
    sql: ${TABLE}.acct_rcvr_mo_01_am ;;
    label: "Total Recoveries"
    description: "Sum of month-one recovery amounts in USD; tracks dollars recovered after write-off in the reporting window."
    value_format_name: usd
  }
}

derived_table_views:
view: risk_acct_triumph_consumer {
  derived_table: {
    sql:
      SELECT acct_cust_xref_id,
             acct_bal_age_mth01_cd,
             acct_bill_bal_mth01_amt,
             acct_wrt_off_am,
             acct_rcvr_mo_01_am,
             acct_bus_unit_cd,
             acct_as_of_dt
      FROM `axp-lumi.dw.risk_pers_acct_history`
      WHERE acct_srce_sys_cd = 'TRIUMPH'
        AND acct_bus_unit_cd IN (1, 2)
    ;;
    persist_for: "24 hours"
  }

  dimension: acct_cust_xref_id {
    primary_key: yes
    type: string
    sql: ${TABLE}.acct_cust_xref_id ;;
    description: "Account-to-customer cross-reference id; primary key after structural filters bake in TRIUMPH consumer scope."
  }

  dimension: delinquency_age_bucket {
    type: string
    sql: CASE
      WHEN TRIM(${TABLE}.acct_bal_age_mth01_cd) IN ('00','01') THEN 'Current'
      WHEN TRIM(${TABLE}.acct_bal_age_mth01_cd) = '02' THEN '30 DPB'
      WHEN TRIM(${TABLE}.acct_bal_age_mth01_cd) = '03' THEN '60 DPB'
      WHEN TRIM(${TABLE}.acct_bal_age_mth01_cd) = '04' THEN '90 DPB'
      WHEN TRIM(${TABLE}.acct_bal_age_mth01_cd) = '05' THEN '120 DPB'
      WHEN TRIM(${TABLE}.acct_bal_age_mth01_cd) = '06' THEN '150 DPB'
      WHEN TRIM(${TABLE}.acct_bal_age_mth01_cd) IN ('07','08','09') THEN '180+ DPB'
      WHEN TRIM(${TABLE}.acct_bal_age_mth01_cd) = '99' THEN 'Written Off'
      ELSE 'NA/Other'
    END ;;
    label: "Delinquency Age Bucket"
    description: "Account aging in delinquency buckets derived from the balance age code; DPB = days past billing."
    order_by_field: delinquency_age_bucket_sort
    tags: ["delinquency", "aging", "past_due", "dpb"]
  }

  dimension: delinquency_age_bucket_sort {
    type: number
    hidden: yes
    sql: CASE
      WHEN TRIM(${TABLE}.acct_bal_age_mth01_cd) IN ('00','01') THEN 1
      WHEN TRIM(${TABLE}.acct_bal_age_mth01_cd) = '02' THEN 2
      WHEN TRIM(${TABLE}.acct_bal_age_mth01_cd) = '03' THEN 3
      WHEN TRIM(${TABLE}.acct_bal_age_mth01_cd) = '04' THEN 4
      WHEN TRIM(${TABLE}.acct_bal_age_mth01_cd) = '05' THEN 5
      WHEN TRIM(${TABLE}.acct_bal_age_mth01_cd) = '06' THEN 6
      WHEN TRIM(${TABLE}.acct_bal_age_mth01_cd) IN ('07','08','09') THEN 7
      WHEN TRIM(${TABLE}.acct_bal_age_mth01_cd) = '99' THEN 8
      ELSE 9
    END ;;
    description: "Sort key enforcing business-correct ordering of delinquency buckets; hidden helper for delinquency_age_bucket."
  }

  dimension_group: acct_as_of {
    type: time
    timeframes: [raw, date, week, month, quarter, year]
    datatype: date
    convert_tz: no
    sql: ${TABLE}.acct_as_of_dt ;;
    description: "Snapshot date for the TRIUMPH consumer account scope, retained from the source for monthly reporting alignment."
  }

  measure: total_ar {
    type: sum
    sql: ${TABLE}.acct_bill_bal_mth01_amt ;;
    label: "Total AR (TRIUMPH Consumer)"
    description: "Sum of month-one billed balance scoped to TRIUMPH consumer business units; the AR measure for this derived view."
    value_format_name: usd
  }

  measure: total_writeoffs {
    type: sum
    sql: ${TABLE}.acct_wrt_off_am ;;
    label: "Total Write-offs (TRIUMPH Consumer)"
    description: "Sum of write-off dollars scoped to TRIUMPH consumer accounts during the snapshot period."
    value_format_name: usd
  }

  measure: total_recoveries {
    type: sum
    sql: ${TABLE}.acct_rcvr_mo_01_am ;;
    label: "Total Recoveries (TRIUMPH Consumer)"
    description: "Sum of month-one recovery dollars scoped to TRIUMPH consumer accounts; pairs with total_writeoffs for net loss."
    value_format_name: usd
  }
}

explore_lkml:
explore: risk_acct_triumph_consumer {
  label: "TRIUMPH Consumer Risk Analysis"
  description: "Account-level delinquency, AR, write-offs, and recoveries for TRIUMPH source on consumer business units 1-2. Answers questions about portfolio aging, recovery efficiency, and write-off trends by delinquency bucket."

  always_filter: {
    filters: [risk_acct_triumph_consumer.acct_as_of_date: "last 12 months"]
  }
}
